#!/bin/bash
set -e
cd "$(dirname "$0")"
python3 -c "import base64; open('scripts/daily-agent.mjs', 'wb').write(base64.b64decode(''))"
git add scripts/daily-agent.mjs
git commit -m "fix: add Next.js file path rules to agent prompt (no Astro/src/pages)"
git push origin main
echo "✅ 完了！次回から正しいパスでmeta更新されます"
